  }

  try {
    // 先读取当前表格，确定最后一行索引
    const existingRows = await readTableAll(docToken, tableBlockId);
    const startRow = existingRows.length; // 从下一行开始追加

    log(`表格现有 ${existingRows.length} 行，将从第 ${startRow + 1} 行开始追加`, 'info');

    // 转换为表格需要的格式：2D 数组
    const values = rows;

    const result = await feishu_doc({
      action: "write_table_cells",
      doc_token: docToken,
      table_block_id: tableBlockId,
      values: values
    });

    log(`✅ 成功写入 ${rows.length} 行数据`, 'success');
    return { success: true, cellsWritten: rows.length * 8, result };

  } catch (error) {
    log(`❌ 写入飞书失败: ${error.message}`, 'error');
    return { success: false, error: error.message };
  }
}

